743 /// We only care about an affine AddRec at the moment. For an affine AddRec,
744 /// the monotonicity can be inferred from its nowrap property. For example, let
745 /// X and Y be loop-invariant, and assume Y is non-negative. An AddRec
746 /// {X,+.Y}<nsw> implies:
747 ///
748 ///   X <=s (X + Y) <=s ((X + Y) + Y) <=s ...
749 ///
750 /// Thus, we can conclude that the AddRec is monotonically increasing with
751 /// respect to the associated loop in a signed sense. The similar reasoning
752 /// applies when Y is non-positive, leading to a monotonically decreasing
753 /// AddRec.
754 SCEVMonotonicity
755 SCEVMonotonicityChecker::visitAddRecExpr(const SCEVAddRecExpr *Expr) {
756   if (!Expr->isAffine() || !Expr->hasNoSignedWrap())
757     return createUnknown(Expr);
758 
759   const SCEV *Start = Expr->getStart();
760   const SCEV *Step = Expr->getStepRecurrence(*SE);
761 
762   SCEVMonotonicity StartMon = visit(Start);
763   if (StartMon.isUnknown())
764     return StartMon;
765 
766   if (!isLoopInvariant(Step))
767     return createUnknown(Expr);
768 
769   return SCEVMonotonicity(SCEVMonotonicityType::MultivariateSignedMonotonic);
770 }
