1245   const SCEV *DstConst = Dst->getStart();
1246   LLVM_DEBUG(dbgs() << "\tStrong SIV test\n");
1247   LLVM_DEBUG(dbgs() << "\t    Coeff = " << *Coeff);
1248   LLVM_DEBUG(dbgs() << ", " << *Coeff->getType() << "\n");
1249   LLVM_DEBUG(dbgs() << "\t    SrcConst = " << *SrcConst);
1250   LLVM_DEBUG(dbgs() << ", " << *SrcConst->getType() << "\n");
