1344     if ((DeltaMaybeNegative && CoeffMaybePositive) ||
1345         (DeltaMaybePositive && CoeffMaybeNegative))
1346       NewDirection |= Dependence::DVEntry::GT;
1347     if (NewDirection < Result.DV[Level].Direction)
1348       ++StrongSIVsuccesses;
1349     Result.DV[Level].Direction &= NewDirection;
1350   }
